// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

export function getCertificate(id: number): Certificate | undefined {
  return certificates.find((c) => c.id === id);
}

export function getCoursesByCertificate(certId: number): Course[] {
  return courses.filter((c) => c.certificateId === certId);
}

export function getCourse(id: number): Course | undefined {
  return courses.find((c) => c.id === id);
}
